	[NodeCategory("Strings")]
	[NodeName("To String", false)]
	[NodeOverload("Core.Operators.ToString")]
	public class ToString_object : ObjectFunctionNode<ExecutionContext, string>
	{
		public ObjectArgument<object> Object;

		public ObjectArgument<string> Format;

		public ObjectArgument<IFormatProvider> FormatProvider;

		protected override string Compute(ExecutionContext context)
		{
			try
			{
				object obj = Configuration.WrapToString(0.ReadObject<object>(context));
				if (obj is IFormattable formattable)
				{
					return formattable.ToString(1.ReadObject<string>(context), 2.ReadObject<IFormatProvider>(context));
				}
				return obj?.ToString();
			}
			catch (FormatException ex)
			{
				return "FORMAT ERROR: " + ex.Message;
			}
		}
	}
