			int num2 = MathX.Clamp(1.ReadValue<int>(context), 0, 10);
			int num3 = (int)num;
			float num4 = num - (float)num3;
			int num5 = num3 / 60;
			num3 %= 60;
			int num6 = num5 / 60;
			num5 %= 60;
			string text = null;
			IFormatProvider formatProvider = 2.ReadObject<IFormatProvider>(context);
			if (num2 > 0)
			{
				text = num4.ToString("F" + num2, formatProvider).Substring(1);
			}
			return num6.ToString(formatProvider) + ":" + num5.ToString("D2", formatProvider) + ":" + num3.ToString("D2", formatProvider) + text;
		}
	}
