	[NodeCategory("Strings")]
	public class ReverseString : ObjectFunctionNode<ExecutionContext, string>
	{
		public ObjectArgument<string> A;

		protected override string Compute(ExecutionContext context)
		{
			string text = 0.ReadObject<string>(context);
			if (string.IsNullOrEmpty(text) || text.Length == 1)
			{
				return text;
			}
			StringBuilder stringBuilder = Pool.BorrowStringBuilder();
			for (int num = text.Length - 1; num >= 0; num--)
			{
				if (num > 0 && char.IsSurrogatePair(text, num - 1))
				{
					stringBuilder.Append(text[num - 1]);
					stringBuilder.Append(text[num]);
					num--;
				}
				else
				{
					stringBuilder.Append(text[num]);
				}
			}
			string result = stringBuilder.ToString();
			Pool.Return(ref stringBuilder);
			return result;
		}
	}
