	[NodeOverload("Core.Math.MultiLerp")]
	[FeatureUpgradeReplacement("ColorManagement", 0, "color", "colorX")]
	public class ValueMultiLerp<T> : ValueFunctionNode<ExecutionContext, T> where T : unmanaged
	{
		public readonly ValueInputList<T> Operands;

		public ValueArgument<float> Lerp;

		public static bool IsValidGenericType => Coder<T>.SupportsLerp;

		protected override T Compute(ExecutionContext context)
		{
			if (Operands.Count == 0)
			{
				return Coder<T>.Default;
			}
			float num = 0.ReadValue<float>(context);
			if (float.IsNaN(num))
			{
				return Coder<T>.Lerp(default(T), default(T), float.NaN);
			}
			if (num <= 0f)
			{
				return Operands.Evaluate(0, context);
			}
			if (num >= (float)(Operands.Count - 1))
			{
				return Operands.Evaluate(Operands.Count - 1, context);
			}
			int num2 = (int)num;
			num -= (float)num2;
			return Coder<T>.Lerp(Operands.Evaluate(num2, context), Operands.Evaluate(num2 + 1, context), num);
		}

		public ValueMultiLerp()
		{
			((ValueMultiLerp<>)(object)this).Operands = new ValueInputList<T>();
		}
	}
