namespace ProtoFlux.Runtimes.Execution.Nodes.Math.Physics
{
	[NodeCategory("Math/Physics")]
	public class TrajectoryPosition : ValueFunctionNode<ExecutionContext, float3>
	{
		public ValueArgument<float3> InitialVelocity;

		public ValueArgument<float3> Gravity;

		public ValueArgument<float> Drag;

		public ValueArgument<float> Time;

		protected override float3 Compute(ExecutionContext context)
		{
			float num = 2.ReadValue<float>(context);
			float3 v = -1.ReadValue<float3>(context);
			float num2 = 3.ReadValue<float>(context);
			float3 v2 = 0.ReadValue<float3>(context);
			float num3 = MathX.Exp((0f - num) * num2);
			float num4 = MathX.Exp(num * num2);
			float num5 = 1f / MathX.Pow(num, 2f);
			return num3 * (num4 * (-v * num * num2 + num * v2 + v) - num * v2 - v) * num5;
		}
	}
	[NodeCategory("Math/Physics")]
	public class TorqueEstimate : ValueFunctionNode<ExecutionContext, floatQ>
	{
		public ValueArgument<float3> InitialTorque;

		public ValueArgument<float> Drag;

		public ValueArgument<float> Time;

		protected override floatQ Compute(ExecutionContext context)
		{
			float num = 1.ReadValue<float>(context);
			float num2 = 2.ReadValue<float>(context);
			float3 v = 0.ReadValue<float3>(context);
			float num3 = MathX.Exp((0f - num) * num2);
			float num4 = MathX.Exp(num * num2);
			float num5 = 1f / MathX.Pow(num, 2f);
			float3 rotation = num3 * (num4 * num * v - num * v) * num5;
			if (!rotation.IsValid())
			{
				return floatQ.Identity;
			}
			return floatQ.Euler(in rotation);
		}
	}
}
