	[NodeCategory("Transform/Bounds")]
	public class BoundingBoxProperties : VoidNode<ExecutionContext>
	{
		public ValueArgument<BoundingBox> Bounds;

		public readonly ValueOutput<float3> Min;

		public readonly ValueOutput<float3> Max;

		public readonly ValueOutput<float3> Center;

		public readonly ValueOutput<float3> Size;

		public readonly ValueOutput<bool> Valid;

		public readonly ValueOutput<bool> Empty;

		protected override void ComputeOutputs(ExecutionContext context)
		{
			BoundingBox boundingBox = 0.ReadValue<BoundingBox>(context);
			Min.Write(boundingBox.min, context);
			Max.Write(boundingBox.max, context);
			Center.Write(boundingBox.Center, context);
			Size.Write(boundingBox.Size, context);
			Valid.Write(boundingBox.IsValid, context);
			Empty.Write(boundingBox.IsEmpty, context);
		}

		public BoundingBoxProperties()
