	public class HalfAdder : VoidNode<ExecutionContext>
	{
		public ValueArgument<bool> A;

		public ValueArgument<bool> B;

		public readonly ValueOutput<bool> Y;

		public readonly ValueOutput<bool> CarryOut;

		protected override void ComputeOutputs(ExecutionContext context)
		{
