	[NodeCategory("Utility/Binary")]
	public class BooleanCounter : VoidNode<ExecutionContext>
	{
		public readonly ValueArgumentList<bool> Booleans;

		public readonly ValueOutput<int> TrueCount;

		public readonly ValueOutput<int> FalseCount;

		public readonly ValueOutput<int> TotalCount;

		protected override void ComputeOutputs(ExecutionContext context)
		{
			int count = Booleans.Count;
			int num = 0;
			for (int i = 0; i < Booleans.Count; i++)
			{
				if (Booleans.ReadValue(i, context, 0))
				{
					num++;
				}
			}
			int value = count - num;
			TrueCount.Write(num, context);
			FalseCount.Write(value, context);
			TotalCount.Write(count, context);
		}

		public BooleanCounter()
		{
			Booleans = new ValueArgumentList<bool>();
			TrueCount = new ValueOutput<int>(this);
			FalseCount = new ValueOutput<int>(this);
			TotalCount = new ValueOutput<int>(this);
		}
	}
