namespace ProtoFlux.Runtimes.Execution.Nodes.Actions
{
	public abstract class IncrementBase<C, T> : WriteBase<C, T> where C : ExecutionContext where T : unmanaged
	{
		protected override T GetValue(IVariable<C, T> variable, C context)
		{
			return Coder<T>.Add(variable.Read(context), Coder<T>.Identity);
		}
	}
	public abstract class DecrementBase<C, T> : WriteBase<C, T> where C : ExecutionContext where T : unmanaged
	{
		protected override T GetValue(IVariable<C, T> variable, C context)
		{
			return Coder<T>.Sub(variable.Read(context), Coder<T>.Identity);
		}
	}
	[NodeName("Indirect Increment", false)]
	[NodeCategory("Actions/Indirect")]
	[NodeOverload("Core.IndirectIncrement")]
	public class ValueIndirectIncrement<C, T> : IncrementBase<C, T> where C : ExecutionContext where T : unmanaged
	{
		public ObjectInput<IVariable<C, T>> Variable;

		protected override IVariable<C, T> GetVariable(C context)
		{
			return Variable.Evaluate(context);
		}
	}
	[NodeName("++", false)]
	[NodeCategory("Actions")]
	[NodeOverload("Core.Increment")]
	public class ValueIncrement<C, T> : IncrementBase<C, T> where C : ExecutionContext where T : unmanaged
	{
		public Reference<IVariable<C, T>> Variable;

		protected override IVariable<C, T> GetVariable(C context)
		{
			return Variable.Target;
		}
	}
	[NodeName("Indirect Decrement", false)]
	[NodeCategory("Actions/Indirect")]
	[NodeOverload("Core.IndirectDecrement")]
	public class ValueIndirectDecrement<C, T> : DecrementBase<C, T> where C : ExecutionContext where T : unmanaged
	{
		public ObjectInput<IVariable<C, T>> Variable;

		protected override IVariable<C, T> GetVariable(C context)
		{
			return Variable.Evaluate(context);
		}
	}
	[NodeName("--", false)]
	[NodeCategory("Actions")]
	[NodeOverload("Core.Decrement")]
	public class ValueDecrement<C, T> : DecrementBase<C, T> where C : ExecutionContext where T : unmanaged
	{
		public Reference<IVariable<C, T>> Variable;

		protected override IVariable<C, T> GetVariable(C context)
		{
			return Variable.Target;
		}
	}
