	{
	}
	public class ValueIndirectDecrement<T> : ValueIndirectDecrement<ExecutionContext, T> where T : unmanaged
	{
	}
	public class ValueIncrement<T> : ValueIncrement<ExecutionContext, T> where T : unmanaged
	{
	}
	public class ValueDecrement<T> : ValueDecrement<ExecutionContext, T> where T : unmanaged
	{
	}
	[NodeCategory("Flow")]
	public class PulseRandom : ActionNode<ExecutionContext>
	{
		public readonly ContinuationList Impulses;

		protected override IOperation Run(ExecutionContext context)
		{
			if (Impulses.Count == 0)
			{
				return null;
			}
			if (Impulses.Count == 1)
			{
				return Impulses.GetImpulseTarget(0);
			}
			int index = RandomX.Range(Impulses.Count);
			return Impulses.GetImpulseTarget(index);
		}

		public PulseRandom()
		{
			Impulses = new ContinuationList();
		}
	}
